(function(){
  function enhanceOutfit(){
    var main=document.querySelector('.detail-container.ready');
    if(!main||document.body.classList.contains('outfit-commerce-ready')) return;
    var items=Array.prototype.slice.call(main.querySelectorAll('.item-link'));
    if(!items.length) return;

    document.body.classList.add('outfit-commerce-ready');
    var list=main.querySelector('.items-list');
    if(list){
      list.id='shop-items';
      list.classList.add('shop-anchor');
    }
    var sectionTitle=main.querySelector('.section-title span:first-child');
    if(sectionTitle) sectionTitle.textContent='CHỌN MÓN ĐỂ MUA';
    var description=main.querySelector('.outfit-desc');
    if(description) description.textContent='Chọn món bạn cần để xem sản phẩm phù hợp trên Shopee.';
    var relatedLabel=document.querySelector('.related-label');
    if(relatedLabel) relatedLabel.textContent='XEM THÊM OUTFIT CÙNG PHONG CÁCH';

    var labels=['áo','quần','giày','phụ kiện'];
    items.forEach(function(item,index){
      var title=item.querySelector('.item-text h3');
      var label=(title&&title.textContent.trim().toLocaleLowerCase('vi'))||labels[index]||'sản phẩm';
      var text=item.querySelector('.item-text p');
      if(text&&!item.classList.contains('no-link')) text.textContent='Món trong outfit';
      var icon=item.querySelector('.item-icon');
      if(icon){
        icon.className='item-number';
        icon.textContent=String(index+1).padStart(2,'0');
      }
      var arrow=item.querySelector('.item-arrow');
      if(arrow&&!item.classList.contains('no-link')){
        arrow.classList.add('item-shop-cta');
        arrow.innerHTML='<span class="desktop-cta">XEM TRÊN SHOPEE</span><span class="mobile-cta">MUA</span><b aria-hidden="true">↗</b>';
      }
      if(!item.classList.contains('no-link')) item.setAttribute('aria-label','Xem '+label+' trên Shopee, mở trong tab mới');
    });

    if(list&&!main.querySelector('.shop-disclosure')){
      var note=document.createElement('p');
      note.className='shop-disclosure';
      note.textContent='Liên kết dẫn đến Shopee. Giá và tình trạng sản phẩm có thể thay đổi.';
      list.insertAdjacentElement('afterend',note);
    }

    if(!document.querySelector('.mobile-shop-cta')){
      var mobileCta=document.createElement('a');
      mobileCta.className='mobile-shop-cta';
      mobileCta.href='#shop-items';
      mobileCta.innerHTML='<span>XEM '+items.filter(function(item){return !item.classList.contains('no-link');}).length+' MÓN TRONG OUTFIT</span><b aria-hidden="true">↓</b>';
      document.body.appendChild(mobileCta);
    }

    var slider=main.querySelector('.slider-wrapper');
    if(slider&&typeof window.moveSlide==='function'){
      var startX=null;
      slider.addEventListener('touchstart',function(event){startX=event.changedTouches[0].clientX;},{passive:true});
      slider.addEventListener('touchend',function(event){
        if(startX===null) return;
        var delta=event.changedTouches[0].clientX-startX;
        startX=null;
        if(Math.abs(delta)>45) window.moveSlide(delta>0?-1:1);
      },{passive:true});
    }
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',enhanceOutfit);
  else enhanceOutfit();
})();
